noncompliant:
struct S1 *p1;
struct S2 *p2;
void f() {
  (float) p1; // Noncompliant: conversion to floating point type
  (int *) p1; // Noncompliant: conversion to incompatible pointer type
  float f;
  int *i = (int *)&f; // Noncompliant: undefined behavior
  (struct S2 *)p1; // Noncompliant: conversion to another struct type
}

compliant:
struct S1 *p1;
void f() {
  (void *) p1; // Compliant: conversion to void pointer
  (intptr_t) p1; // Compliant: conversion to integer type that can hold pointer
  struct S1 *p2 = p1; // Compliant: same type assignment
  char *bytes = (char *)p1; // Compliant: char* can alias any object
}
